// UC6: Detect stuck deals based on configurable thresholds
// Thresholds can be overridden per-tenant in tenant_configs
const tenantId = $env.TENANT_ID;

// Default stagnation thresholds by stage keyword (days)
// These are conservative — real deal will vary by industry
const STAGE_THRESHOLDS = {
  default: 10,
  demo: 7,
  proposal: 14,
  contract: 7,
  negotiation: 21,
  discovery: 14,
  qualified: 10,
  trial: 14,
  review: 10,
};

function getThreshold(stage) {
  if (!stage) return STAGE_THRESHOLDS.default;
  const s = stage.toLowerCase();
  for (const [key, days] of Object.entries(STAGE_THRESHOLDS)) {
    if (key !== 'default' && s.includes(key)) return days;
  }
  return STAGE_THRESHOLDS.default;
}

const deals = $input.all().map(i => i.json);

if (!deals || deals.length === 0) {
  return [{ json: { skipped: true, reason: 'No open deals found', tenant_id: tenantId } }];
}

const stuck = deals.filter(d => {
  const threshold = getThreshold(d.stage);
  const daysStuck = parseInt(d.days_in_stage) || 0;
  return daysStuck >= threshold;
});

console.log(`[02-pipeline] ${deals.length} open deals, ${stuck.length} stuck`);

if (stuck.length === 0) {
  return [{ json: { skipped: true, reason: 'No stuck deals detected', total_deals: deals.length } }];
}

// Sort by value — biggest deals first
stuck.sort((a, b) => parseFloat(b.amount || 0) - parseFloat(a.amount || 0));

// Cap at 10 to avoid LLM cost explosion
return stuck.slice(0, 10).map(d => ({ json: { ...d, _is_stuck: true } }));

const deal = $('Detect Stuck Deals (UC6)').first().json;
const ragRows = $('Supabase — RAG Deal Patterns').all().map(i => i.json);

const ragExamples = ragRows.length > 0
  ? ragRows.map((r, i) => {
      const m = r.metadata || {};
      return `Example ${i+1}: Stage=${m.stage || 'unknown'}, Action=${m.action || 'N/A'}, Outcome=${m.outcome_score || '?'}%`;
    }).join('\n')
  : 'No past examples — use best judgment.';

const stageDays = parseInt(deal.days_in_stage) || 0;
const dealValue = parseFloat(deal.amount || 0).toLocaleString();

const prompt = `You are an expert sales analyst. A deal is stuck.

DEAL DATA
Name: ${deal.name}
Stage: ${deal.stage}
Days stuck in current stage: ${stageDays}
Deal value: $${dealValue}
Close probability: ${deal.probability}%
Contact: ${deal.contact_name || 'Unknown'} (${deal.contact_role || 'Unknown role'})
Last activity: ${deal.last_activity_at || 'Unknown'}

SIMILAR PAST UNBLOCKS
${ragExamples}

ANALYZE AND OUTPUT STRICTLY in this format:
DIAGNOSIS:
[1-2 sentences — what is likely causing this deal to stall? Be specific.]

BLOCKING_FACTOR: [TIMING|BUDGET|AUTHORITY|NEED|TRUST|COMPETITOR|UNKNOWN]

ACTION:
[1 sentence — exact action: channel (email/call/LinkedIn) + specific hook or angle. Not 'follow up'.]

RISK_IF_NO_ACTION:
[1 sentence — what happens to this deal if nothing is done this week?]`;

return [{ json: { ...deal, _unblock_prompt: prompt } }];

const deal     = $('Build Unblock Prompt (UC7)').first().json;
const raw      = $('Claude — Analyze & Recommend Unblock').first().json.content?.[0]?.text || '';
const validated = $input.first().json;

const finalText = validated.valid ? validated.output : raw;
const warnings  = validated.warnings || [];
if (!validated.valid) warnings.push('Validation failed — using raw LLM output, review before acting');

// Extract structured fields
const diagMatch    = finalText.match(/DIAGNOSIS:\s*([\s\S]*?)(?:BLOCKING_FACTOR:|$)/i);
const factorMatch  = finalText.match(/BLOCKING_FACTOR:\s*(\w+)/i);
const actionMatch  = finalText.match(/ACTION:\s*([\s\S]*?)(?:RISK_IF_NO_ACTION:|$)/i);
const riskMatch    = finalText.match(/RISK_IF_NO_ACTION:\s*([\s\S]*?)$/i);

return [{
  json: {
    deal_id:         deal.id,
    deal_name:       deal.name,
    deal_amount:     deal.amount,
    deal_stage:      deal.stage,
    days_in_stage:   deal.days_in_stage,
    contact_email:   deal.contact_email,
    diagnosis:       diagMatch?.[1]?.trim() || 'Analysis unavailable',
    blocking_factor: factorMatch?.[1]?.trim() || 'UNKNOWN',
    action:          actionMatch?.[1]?.trim() || 'Manual review required',
    risk:            riskMatch?.[1]?.trim() || '',
    full_analysis:   finalText,
    validation_warnings: warnings,
    tenant_id:       $env.TENANT_ID
  }
}];

// Build next-best-action prompt (UC5) for all actionable leads
// Runs in parallel to stuck deal analysis
const deals = $('Detect Stuck Deals (UC6)').all().map(i => i.json);

// UC5 — generate NBA for top 3 stuck deals by value
const top3 = deals.slice(0, 3);
return top3.map(d => ({
  json: {
    ...d,
    _nba_prompt: `You are a senior sales strategist. For this deal, what is the single best action to take RIGHT NOW?

Deal: ${d.name}
Stage: ${d.stage}
Days stuck: ${d.days_in_stage}
Value: $${parseFloat(d.amount || 0).toLocaleString()}
Contact: ${d.contact_name || 'Unknown'}

OUTPUT strictly:
ACTION_TYPE: [email|call|linkedin|meeting|proposal_revision|price_negotiation]
CHANNEL: [email|phone|linkedin|in_person]
MESSAGE_ANGLE: [1 sentence — the hook or angle to use]
URGENCY: [HIGH|MEDIUM|LOW]
RATIONALE: [1 sentence — why this specific action now]`
  }
}));

const data = $input.first().json;
const names   = data.deal_name || [];
const days    = data.days_in_stage || [];
const amounts = data.deal_amount || [];
const factors = data.blocking_factor || [];
const actions = data.action || [];

if (names.length === 0) {
  return [{ json: { slack_message: '✅ Pipeline looks healthy — no stuck deals today.' } }];
}

const lines = names.map((n, i) =>
  `*${n}* — ${days[i]} days stuck · $${parseFloat(amounts[i] || 0).toLocaleString()}\n  🔍 ${factors[i] || 'UNKNOWN'} · ${actions[i] || 'Review manually'}`);

const msg = `🚨 *Pipeline Alert — ${names.length} stuck deal(s)*\n\n${lines.join('\n\n')}\n\n_Review the approval queue in your dashboard._`;
return [{ json: { slack_message: msg } }];
